Add: (1) retry with backoff for transient tool failures, (2) a max iterations guard, (3) graceful failure message that reports progress so far.

explanation:
```js
let iterations = 0;
const progress = [];
while (true) {
  if (++iterations > 20) return { partial: true, progress, message: 'Max iterations reached. Progress so far: ' + progress.join(', ') };
  const response = await client.messages.create({ model, messages, tools });
  if (response.stop_reason === 'end_turn') return { success: true, result: response.content[0].text };
  const tool = response.content.find(b => b.type === 'tool_use');
  let result;
  try {
    result = await retryWithBackoff(() => executeTool(tool.name, tool.input));
    progress.push(`${tool.name}: success`);
  } catch (e) {
    result = { success: false, error: e.message };
    progress.push(`${tool.name}: failed (${e.message})`);
  }
  messages.push({ role: 'assistant', content: response.content });
  messages.push({ role: 'user', content: [{ type: 'tool_result', tool_use_id: tool.id, content: JSON.stringify(result) }] });
}
```
